from dbos import DBOS, DBOSConfig
import anthropic

# Configure DBOS — points at your Postgres database
DBOS(config=DBOSConfig(
    name="research-agent",
    database_url="postgresql://user:pass@localhost:5432/myapp",
))

llm = anthropic.Anthropic()

# @DBOS.step() — marks a function as a durable step
# On retry: if this step completed before the crash, DBOS replays the stored result
@DBOS.step()
def generate_outline(topic: str) -> str:
    return llm.messages.create(
        model="claude-sonnet-5",
        max_tokens=500,
        messages=[{"role": "user", "content": f"Create a 5-section outline for: {topic}"}],
    ).content[0].text


@DBOS.step()
def generate_section(title: str, index: int) -> str:
    return llm.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=300,
        messages=[{"role": "user", "content": f"Write section {index+1}: {title}"}],
    ).content[0].text


# @DBOS.workflow() — the orchestration function, persisted in Postgres
@DBOS.workflow()
def research_workflow(topic: str) -> str:
    outline = generate_outline(topic)           # durable step call
    sections = []
    for i, title in enumerate(outline.split("\n")[:5]):
        content = generate_section(title, i)    # each section is a separate step
        sections.append(content)
    return "\n\n".join(sections)

from dbos import DBOS

APPROVAL_EVENT = "doc-approval"

@DBOS.workflow()
def document_review_workflow(doc_id: str) -> str:
    # Generate a summary (durable step)
    summary = generate_summary(doc_id)

    # Pause and wait for an external approval event (up to 7 days)
    approval = DBOS.recv(APPROVAL_EVENT, timeout_seconds=7 * 24 * 3600)

    if approval is None:
        return f"Timeout: {doc_id}"

    if approval.get("approved"):
        publish_document(doc_id)
        return f"Published: {doc_id}"
    else:
        return f"Rejected: {doc_id}"


# From a separate process / webhook handler — send the approval signal
def handle_approval_webhook(doc_id: str, approved: bool):
    workflow_handle = DBOS.retrieve_workflow(f"review-{doc_id}")
    DBOS.send(
        workflow_handle.workflow_id,
        {"approved": approved, "doc_id": doc_id},
        topic=APPROVAL_EVENT,
    )

