from dbos import DBOS, Queue
import httpx

dbos = DBOS()
order_queue = Queue("order-processing", concurrency=5)

@DBOS.step()
def validate_order(order_id: str) -> dict:
    resp = httpx.get(f"https://api.example.com/orders/{order_id}")
    resp.raise_for_status()
    return resp.json()

@DBOS.step()
def charge_payment(order_id: str, amount: float) -> str:
    resp = httpx.post("https://payments.example.com/charge",
                      json={"order_id": order_id, "amount": amount})
    resp.raise_for_status()
    return resp.json()["transaction_id"]

@DBOS.step()
def ship_order(order_id: str, txn_id: str) -> None:
    httpx.post("https://fulfillment.example.com/ship",
               json={"order_id": order_id, "transaction_id": txn_id})

@DBOS.workflow()
def process_order(order_id: str) -> str:
    order = validate_order(order_id)
    txn_id = charge_payment(order_id, order["total"])
    ship_order(order_id, txn_id)
    return txn_id

# Enqueue — up to 5 run concurrently, rest wait in Postgres
def submit_order(order_id: str):
    handle = order_queue.enqueue(process_order, order_id)
    return handle.workflow_id

from dbos import DBOS
import httpx

MAX_RETRIES = 3

@DBOS.step()
def fetch_with_retry(url: str) -> dict:
    # DBOS replays this entire step on crash — so it must be idempotent.
    # For non-idempotent steps (payments), use SetWorkflowID instead.
    resp = httpx.get(url, timeout=10.0)
    resp.raise_for_status()
    return resp.json()

@DBOS.workflow()
def resilient_pipeline(urls: list[str]) -> list[dict]:
    results = []
    for url in urls:
        try:
            data = fetch_with_retry(url)
            results.append(data)
        except Exception as e:
            # Workflow catches the exception; Postgres records the failure.
            # The workflow itself continues — partial results are preserved.
            results.append({"url": url, "error": str(e)})
    return results
